  `status` varchar(20) NOT NULL,
  `elapsed_time` int DEFAULT NULL,
  `h2h_data` json DEFAULT NULL,
  `predictions_data` json DEFAULT NULL,
  `statistics_data` json DEFAULT NULL,
  `api_id` varchar(255) DEFAULT NULL,
  `away_corners` int DEFAULT NULL,
  `away_fouls` int DEFAULT NULL,
  `away_red` int DEFAULT NULL,
  `away_shots` int DEFAULT NULL,
