  `home_fouls` int DEFAULT NULL,
  `home_red` int DEFAULT NULL,
  `home_shots` int DEFAULT NULL,
  `home_shots_on_target` int DEFAULT NULL,
  `home_yellow` int DEFAULT NULL,
