  KEY `matches_match_away_team_id_d1513cbf_fk_matches_team_id` (`away_team_id`),
  KEY `matches_match_home_team_id_cdfabc57_fk_matches_team_id` (`home_team_id`),
  KEY `matches_match_season_id_09c8c091_fk_matches_season_id` (`season_id`),
