  CONSTRAINT `matches_match_home_team_id_cdfabc57_fk` FOREIGN KEY (`home_team_id`) REFERENCES `matches_team` (`id`),
  CONSTRAINT `matches_match_league_id_85533561_fk` FOREIGN KEY (`league_id`) REFERENCES `matches_league` (`id`),
  CONSTRAINT `matches_match_season_id_09c8c091_fk` FOREIGN KEY (`season_id`) REFERENCES `matches_season` (`id`)
